  var S, p = this;
  return function(i) {
    return A(p, void 0, void 0, function() {
      return a(this, function(r) {
        return i && (S = void 0),  // Clears cache on needFresh
        [2, new Promise(function(t, e) {
          h(i).then(function(o) {
            S = o;  // Store in cache
            t(o);   // Return fresh token
          }).catch(function(o) {
            S !== void 0 && S.length > 0 && t(S);  // FALLBACK: returns stale cached token
            e(o);   // Also rejects (but t() was already called if cache exists)
